package tapNpay;

import javax.swing.*;
import java.awt.*;
import java.awt.event.ActionEvent;
import java.awt.event.ActionListener;
import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.URL;

public class NewJFrame extends JFrame {
    private JPanel contentPane;
    private JTextField urlField;
    private JTextArea responseArea;

    public NewJFrame() {
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        setBounds(100, 100, 450, 300);
        contentPane = new JPanel();
        contentPane.setBorder(new EmptyBorder(5, 5, 5, 5));
        setContentPane(contentPane);
        contentPane.setLayout(new BorderLayout());

        JLabel label = new JLabel("Enter URL:");
        contentPane.add(label, BorderLayout.NORTH);

        urlField = new JTextField(20);
        contentPane.add(urlField, BorderLayout.CENTER);

        JButton button = new JButton("Fetch");
        button.addActionListener(new ActionListener() {
            @Override
            public void actionPerformed(ActionEvent e) {
                fetchURL(urlField.getText());
            }
        });
        contentPane.add(button, BorderLayout.SOUTH);

        responseArea = new JTextArea();
        responseArea.setEditable(false);
        JScrollPane scrollPane = new JScrollPane(responseArea);
        contentPane.add(scrollPane, BorderLayout.EAST);
    }

    private void fetchURL(String urlString) {
        try {
            URL url = new URL(urlString);
            HttpURLConnection connection = (HttpURLConnection) url.openConnection();
            connection.setRequestMethod("GET");

            BufferedReader in = new BufferedReader(new InputStreamReader(connection.getInputStream()));
            String inputLine;
            StringBuilder content = new StringBuilder();
            while ((inputLine = in.readLine()) != null) {
                content.append(inputLine);
            }
            in.close();
            connection.disconnect();

            responseArea.setText(content.toString());
        } catch (IOException e) {
            responseArea.setText("Error: " + e.getMessage());
        } catch (Exception e) {
            responseArea.setText("Error: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        EventQueue.invokeLater(() -> {
            try {
                NewJFrame frame = new NewJFrame();
                frame.setVisible(true);
            } catch (Exception e) {
                e.printStackTrace();
            }
        });
    }
}
